Setting up HTTPS incorrectly is one of the most common cryptographic failures. Many developers either allow weak TLS versions for backward compatibility or use insecure default configurations.

**VULNERABLE CODE**:

```javascript
const https = require('https');
const fs = require('fs');
const express = require('express');

const app = express();

// DANGEROUS: Allowing weak TLS versions
const options = {
  key: fs.readFileSync('server-key.pem'),
  cert: fs.readFileSync('server-cert.pem'),
  // Explicitly enabling outdated protocols for "compatibility"
  secureProtocol: 'SSLv23_method',
  // No minimum version specified - allows TLS 1.0, 1.1
  // Missing: minVersion configuration
  // Weak cipher suites allowed by default
  ciphers: 'ALL:!aNULL'
};

app.get('/api/payment', (req, res) => {
  // Processing sensitive payment data over potentially weak TLS
  res.json({ status: 'payment processed' });
});

https.createServer(options, app).listen(443, () => {
  console.log('HTTPS server running on port 443');
});
```

**Attack Scenario - POODLE Attack**:
```text
1. Attacker positions themselves as MITM (public WiFi, ARP spoofing)
2. Forces TLS downgrade to SSLv3 via handshake manipulation
3. Exploits CBC padding oracle in SSLv3
4. Decrypts one byte of ciphertext per 256 requests on average
5. Extracts session cookies, authentication tokens, credit card data
```

**Why This Is Dangerous**:
- SSLv3 is vulnerable to POODLE attack allowing decryption of encrypted data
- TLS 1.0 is vulnerable to BEAST attack targeting CBC mode ciphers
- TLS 1.1 lacks modern authenticated encryption (AEAD) support
- Using 'ALL' ciphers includes weak export-grade and NULL encryption ciphers
- No Perfect Forward Secrecy means past sessions can be decrypted if server key is compromised

**SECURE VERSION**:

```javascript
const https = require('https');
const fs = require('fs');
const express = require('express');
const tls = require('tls');

const app = express();

// SECURE: Modern TLS configuration
const options = {
  key: fs.readFileSync('server-key.pem'),
  cert: fs.readFileSync('server-cert.pem'),
  // Enforce minimum TLS 1.2 (TLS 1.3 preferred)
  minVersion: 'TLSv1.2',
  maxVersion: 'TLSv1.3',
  // Strong cipher suites only - AEAD ciphers with Perfect Forward Secrecy
  ciphers: [
    'TLS_AES_256_GCM_SHA384',
    'TLS_CHACHA20_POLY1305_SHA256',
    'TLS_AES_128_GCM_SHA256',
    'ECDHE-RSA-AES256-GCM-SHA384',
    'ECDHE-RSA-AES128-GCM-SHA256',
    'ECDHE-ECDSA-AES256-GCM-SHA384',
    'ECDHE-ECDSA-AES128-GCM-SHA256'
  ].join(':'),
  // Prefer server cipher order
  honorCipherOrder: true,
  // Enable session resumption securely
  sessionTimeout: 300,
  // Disable compression (CRIME attack mitigation)
  secureOptions: tls.constants.SSL_OP_NO_COMPRESSION
};

app.get('/api/payment', (req, res) => {
  // Processing sensitive payment data over strong TLS
  res.json({ status: 'payment processed' });
});

https.createServer(options, app).listen(443, () => {
  console.log('Secure HTTPS server running with TLS 1.2+ on port 443');
});
```

**Key Security Controls**:
- `minVersion: 'TLSv1.2'` blocks all connections using SSLv3, TLS 1.0, or TLS 1.1
- AEAD cipher suites (GCM, ChaCha20-Poly1305) provide authenticated encryption immune to padding oracle attacks
- ECDHE key exchange provides Perfect Forward Secrecy - compromised server key cannot decrypt past sessions
- `honorCipherOrder: true` ensures server chooses the strongest mutually-supported cipher
- Disabled TLS compression prevents CRIME attack

Excellent question - outbound HTTPS requests are equally critical. Disabling certificate validation is a common antipattern that completely undermines TLS security.

**PRODUCTION PATTERN**:

```javascript
const https = require('https');
const tls = require('tls');
const fs = require('fs');
const axios = require('axios');

// ============================================
// LAYER 1: Secure HTTPS Agent Configuration
// ============================================
const createSecureAgent = () => {
  return new https.Agent({
    // Enforce TLS 1.2 minimum for all outbound requests
    minVersion: 'TLSv1.2',
    maxVersion: 'TLSv1.3',
    // Strong cipher suites only
    ciphers: [
      'TLS_AES_256_GCM_SHA384',
      'TLS_CHACHA20_POLY1305_SHA256',
      'ECDHE-RSA-AES256-GCM-SHA384',
      'ECDHE-ECDSA-AES256-GCM-SHA384'
    ].join(':'),
    // CRITICAL: Never disable certificate validation
    rejectUnauthorized: true,
    // Optional: Pin to specific CA for high-security endpoints
    // ca: fs.readFileSync('trusted-ca-bundle.pem'),
    // Connection pooling settings
    keepAlive: true,
    maxSockets: 50,
    timeout: 30000
  });
};

// ============================================
// LAYER 2: Secure Axios Client Factory
// ============================================
const createSecureApiClient = (baseURL, options = {}) => {
  const secureAgent = createSecureAgent();

  const client = axios.create({
    baseURL,
    httpsAgent: secureAgent,
    timeout: options.timeout || 10000,
    // Validate response status
    validateStatus: (status) => status >= 200 && status < 300,
    headers: {
      'User-Agent': 'SecureApp/1.0',
      'Accept': 'application/json'
    }
  });

  // Request interceptor for logging
  client.interceptors.request.use(
    (config) => {
      console.log(`[HTTPS] Outbound request to: ${config.baseURL}${config.url}`);
      config.metadata = { startTime: Date.now() };
      return config;
    },
    (error) => {
      console.error('[HTTPS] Request configuration error:', error.message);
      return Promise.reject(error);
    }
  );

  // Response interceptor for TLS validation logging
  client.interceptors.response.use(
    (response) => {
      const duration = Date.now() - response.config.metadata.startTime;
      const socket = response.request?.socket || response.request?.connection;

      if (socket && socket.getPeerCertificate) {
        const cert = socket.getPeerCertificate();
        const tlsVersion = socket.getProtocol();
        const cipher = socket.getCipher();

        console.log('[TLS] Connection details:', {
          tlsVersion,
          cipher: cipher?.name,
          certSubject: cert?.subject?.CN,
          certIssuer: cert?.issuer?.CN,
          certValidTo: cert?.valid_to,
          duration: `${duration}ms`
        });

        // SECURITY CHECK: Reject weak TLS versions even if connection succeeded
        if (tlsVersion && !['TLSv1.2', 'TLSv1.3'].includes(tlsVersion)) {
          console.error(`[SECURITY] Weak TLS version detected: ${tlsVersion}`);
          throw new Error(`Insecure TLS version: ${tlsVersion}`);
        }
      }

      return response;
    },
    (error) => {
      // Log TLS-specific errors for debugging
      if (error.code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE') {
        console.error('[TLS] Certificate verification failed - possible MITM attack');
      } else if (error.code === 'CERT_HAS_EXPIRED') {
        console.error('[TLS] Server certificate has expired');
      } else if (error.code === 'ERR_TLS_CERT_ALTNAME_INVALID') {
        console.error('[TLS] Certificate hostname mismatch');
      }
      return Promise.reject(error);
    }
  );

  return client;
};

// ============================================
// LAYER 3: Certificate Pinning for Critical APIs
// ============================================
const createPinnedClient = (baseURL, expectedFingerprint) => {
  const pinnedAgent = new https.Agent({
    minVersion: 'TLSv1.2',
    rejectUnauthorized: true,
    checkServerIdentity: (hostname, cert) => {
      // Standard hostname verification
      const err = tls.checkServerIdentity(hostname, cert);
      if (err) return err;

      // Certificate fingerprint pinning
      const fingerprint = cert.fingerprint256;
      if (fingerprint !== expectedFingerprint) {
        return new Error(
          `Certificate fingerprint mismatch. Expected: ${expectedFingerprint}, Got: ${fingerprint}`
        );
      }

      console.log(`[TLS] Certificate pinning verified for ${hostname}`);
      return undefined;
    }
  });

  return axios.create({
    baseURL,
    httpsAgent: pinnedAgent,
    timeout: 10000
  });
};

// ============================================
// LAYER 4: Usage Example with Error Handling
// ============================================
const paymentApiClient = createSecureApiClient('https://api.paymentgateway.com');

// For critical payment processor - use certificate pinning
const criticalPaymentClient = createPinnedClient(
  'https://secure.stripe.com',
  'AA:BB:CC:DD:EE:FF:00:11:22:33:44:55:66:77:88:99:AA:BB:CC:DD:EE:FF:00:11:22:33:44:55:66:77:88:99'
);

const processPayment = async (paymentData) => {
  try {
    const response = await paymentApiClient.post('/v1/charges', paymentData);
    return response.data;
  } catch (error) {
    // Handle TLS errors specifically
    if (error.code?.startsWith('ERR_TLS') || error.code?.startsWith('CERT')) {
      console.error('[SECURITY ALERT] TLS error during payment processing:', {
        code: error.code,
        message: error.message,
        timestamp: new Date().toISOString()
      });
      // Alert security team
      // await alertSecurityTeam('TLS_ERROR', error);
    }
    throw new Error('Payment processing failed securely');
  }
};

module.exports = {
  createSecureApiClient,
  createPinnedClient,
  processPayment
};
```

**Defense in Depth Layers**:

1. **Transport Layer** - Enforced TLS 1.2+ with strong AEAD ciphers:
```javascript
minVersion: 'TLSv1.2',
ciphers: 'TLS_AES_256_GCM_SHA384:ECDHE-RSA-AES256-GCM-SHA384'
```

2. **Certificate Validation** - Never disabled, with optional pinning:
```javascript
rejectUnauthorized: true, // NEVER set to false in production
checkServerIdentity: (hostname, cert) => { /* custom pinning logic */ }
```

3. **Runtime Verification** - Post-connection TLS version audit:
```javascript
const tlsVersion = socket.getProtocol();
if (!['TLSv1.2', 'TLSv1.3'].includes(tlsVersion)) {
  throw new Error(`Insecure TLS version: ${tlsVersion}`);
}
```

4. **Monitoring & Alerting** - Comprehensive TLS error logging for security events

**Additional Protections**:
- **Environment Variable Controls**: Set `NODE_TLS_MIN_VERSION=TLSv1.2` as a process-level fallback
- **Certificate Transparency Monitoring**: Subscribe to CT logs for your domains to detect misissued certificates
- **HSTS Preloading**: For your own services, implement HTTP Strict Transport Security
- **Regular Cipher Suite Audits**: Use tools like testssl.sh or SSL Labs to verify configuration
- **Dependency Scanning**: Monitor for vulnerabilities in OpenSSL/BoringSSL bundled with Node.js

Many legacy Java applications still use outdated TLS configurations that are vulnerable to protocol downgrade attacks like POODLE and BEAST. Let me show you what to avoid and how to configure secure connections.

**VULNERABLE CODE**:

```java
import javax.net.ssl.*;
import java.io.*;
import java.net.URL;
import java.security.KeyManagementException;
import java.security.NoSuchAlgorithmException;

public class InsecureSSLClient {

    public String fetchData(String urlString) throws Exception {
        // VULNERABLE: Using SSLv3 or TLS 1.0
        SSLContext sslContext = SSLContext.getInstance("SSLv3");
        sslContext.init(null, null, null);

        HttpsURLConnection.setDefaultSSLSocketFactory(sslContext.getSocketFactory());

        URL url = new URL(urlString);
        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();

        BufferedReader reader = new BufferedReader(
            new InputStreamReader(conn.getInputStream()));
        StringBuilder response = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            response.append(line);
        }
        reader.close();
        return response.toString();
    }

    // VULNERABLE: Trusting all certificates
    public void disableCertificateValidation() throws Exception {
        TrustManager[] trustAllCerts = new TrustManager[]{
            new X509TrustManager() {
                public java.security.cert.X509Certificate[] getAcceptedIssuers() {
                    return null;
                }
                public void checkClientTrusted(
                    java.security.cert.X509Certificate[] certs, String authType) {}
                public void checkServerTrusted(
                    java.security.cert.X509Certificate[] certs, String authType) {}
            }
        };

        SSLContext sc = SSLContext.getInstance("TLSv1"); // VULNERABLE: TLS 1.0
        sc.init(null, trustAllCerts, new java.security.SecureRandom());
        HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory());
    }
}
```

**Attack Scenario** (POODLE Attack):
```text
1. Attacker intercepts TLS handshake via MITM position
2. Forces protocol downgrade to SSLv3 by blocking higher TLS versions
3. Exploits CBC padding oracle in SSLv3
4. Decrypts session cookies one byte at a time (256 requests per byte)
5. Hijacks authenticated session
```

**Why This Is Dangerous**:
- SSLv3 is cryptographically broken (POODLE attack CVE-2014-3566)
- TLS 1.0 vulnerable to BEAST attack (CVE-2011-3389) and Lucky13
- TLS 1.1 has known weaknesses and deprecated by RFC 8996
- Disabling certificate validation allows any MITM attack
- No cipher suite restrictions allows weak encryption

**SECURE VERSION**:

```java
import javax.net.ssl.*;
import java.io.*;
import java.net.URL;
import java.security.KeyStore;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;

public class SecureSSLClient {

    private static final String[] SECURE_PROTOCOLS = {"TLSv1.3", "TLSv1.2"};
    private static final String[] SECURE_CIPHER_SUITES = {
        "TLS_AES_256_GCM_SHA384",
        "TLS_AES_128_GCM_SHA256",
        "TLS_CHACHA20_POLY1305_SHA256",
        "TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256",
        "TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256"
    };

    public String fetchDataSecurely(String urlString) throws Exception {
        // SECURE: Use TLS 1.3/1.2 only
        SSLContext sslContext = SSLContext.getInstance("TLSv1.3");
        sslContext.init(null, null, new java.security.SecureRandom());

        SSLSocketFactory factory = new SecureSSLSocketFactory(sslContext.getSocketFactory());

        URL url = new URL(urlString);
        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();
        conn.setSSLSocketFactory(factory);

        // Enable hostname verification
        conn.setHostnameVerifier(HttpsURLConnection.getDefaultHostnameVerifier());

        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(conn.getInputStream()))) {
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line);
            }
            return response.toString();
        } finally {
            conn.disconnect();
        }
    }

    // Custom SSLSocketFactory that enforces secure protocols and ciphers
    private static class SecureSSLSocketFactory extends SSLSocketFactory {
        private final SSLSocketFactory delegate;

        public SecureSSLSocketFactory(SSLSocketFactory delegate) {
            this.delegate = delegate;
        }

        @Override
        public Socket createSocket(Socket s, String host, int port, boolean autoClose) 
                throws IOException {
            SSLSocket socket = (SSLSocket) delegate.createSocket(s, host, port, autoClose);
            configureSocket(socket);
            return socket;
        }

        private void configureSocket(SSLSocket socket) {
            socket.setEnabledProtocols(SECURE_PROTOCOLS);
            socket.setEnabledCipherSuites(SECURE_CIPHER_SUITES);
        }

        // ... implement other required methods
        @Override public String[] getDefaultCipherSuites() { return SECURE_CIPHER_SUITES; }
        @Override public String[] getSupportedCipherSuites() { return SECURE_CIPHER_SUITES; }
        @Override public Socket createSocket(String host, int port) throws IOException {
            SSLSocket socket = (SSLSocket) delegate.createSocket(host, port);
            configureSocket(socket);
            return socket;
        }
        @Override public Socket createSocket(String host, int port, java.net.InetAddress localHost, int localPort) throws IOException {
            SSLSocket socket = (SSLSocket) delegate.createSocket(host, port, localHost, localPort);
            configureSocket(socket);
            return socket;
        }
        @Override public Socket createSocket(java.net.InetAddress host, int port) throws IOException {
            SSLSocket socket = (SSLSocket) delegate.createSocket(host, port);
            configureSocket(socket);
            return socket;
        }
        @Override public Socket createSocket(java.net.InetAddress address, int port, java.net.InetAddress localAddress, int localPort) throws IOException {
            SSLSocket socket = (SSLSocket) delegate.createSocket(address, port, localAddress, localPort);
            configureSocket(socket);
            return socket;
        }
    }
}
```

**Key Security Controls**:
- **TLS 1.3/1.2 Only**: Explicitly set `TLSv1.3` or `TLSv1.2` as the protocol; never allow SSLv3, TLS 1.0, or TLS 1.1
- **Strong Cipher Suites**: Use only AEAD ciphers (GCM, ChaCha20-Poly1305) with forward secrecy (ECDHE)
- **Certificate Validation**: Never disable certificate validation; use the default trust manager
- **Hostname Verification**: Always verify the server hostname matches the certificate

Server-side TLS configuration is even more critical because it affects all clients connecting to your application. Here's a comprehensive production-ready approach for Spring Boot.

**PRODUCTION PATTERN**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.web.embedded.tomcat.TomcatServletWebServerFactory;
import org.springframework.boot.web.server.Ssl;
import org.springframework.boot.web.server.WebServerFactoryCustomizer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.apache.catalina.connector.Connector;
import org.apache.coyote.http11.Http11NioProtocol;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.annotation.PostConstruct;
import java.security.Security;

@SpringBootApplication
public class SecureTLSApplication {

    private static final Logger logger = LoggerFactory.getLogger(SecureTLSApplication.class);

    public static void main(String[] args) {
        // Disable insecure algorithms globally at JVM level
        Security.setProperty("jdk.tls.disabledAlgorithms", 
            "SSLv3, TLSv1, TLSv1.1, RC4, DES, MD5withRSA, DH keySize < 2048, " +
            "EC keySize < 224, 3DES_EDE_CBC, anon, NULL");

        SpringApplication.run(SecureTLSApplication.class, args);
    }
}

@Configuration
class TLSSecurityConfiguration {

    private static final Logger logger = LoggerFactory.getLogger(TLSSecurityConfiguration.class);

    // Production-grade TLS cipher suites (PCI DSS 4.0 compliant)
    private static final String[] ALLOWED_CIPHERS = {
        "TLS_AES_256_GCM_SHA384",
        "TLS_AES_128_GCM_SHA256",
        "TLS_CHACHA20_POLY1305_SHA256",
        "TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256",
        "TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256"
    };

    private static final String[] ALLOWED_PROTOCOLS = {"TLSv1.3", "TLSv1.2"};

    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> tlsCustomizer() {
        return factory -> {
            factory.addConnectorCustomizers(connector -> {
                Http11NioProtocol protocol = (Http11NioProtocol) connector.getProtocolHandler();

                // Enforce TLS 1.2+ only
                protocol.setSSLProtocol("TLSv1.2+TLSv1.3");
                protocol.setSslEnabledProtocols(String.join(",", ALLOWED_PROTOCOLS));

                // Set strong cipher suites only
                protocol.setCiphers(String.join(",", ALLOWED_CIPHERS));

                // Prefer server cipher order (prevents downgrade attacks)
                protocol.setUseServerCipherSuitesOrder(true);

                // Enable OCSP stapling for certificate validation
                protocol.setSSLDisableSessionTickets(false);

                logger.info("TLS configuration applied: protocols={}, ciphers={}",
                    ALLOWED_PROTOCOLS, ALLOWED_CIPHERS.length + " strong ciphers");
            });

            // Configure SSL
            Ssl ssl = new Ssl();
            ssl.setEnabled(true);
            ssl.setProtocol("TLS");
            ssl.setEnabledProtocols(ALLOWED_PROTOCOLS);
            ssl.setCiphers(ALLOWED_CIPHERS);
            ssl.setKeyStore("classpath:keystore.p12");
            ssl.setKeyStorePassword(System.getenv("KEYSTORE_PASSWORD"));
            ssl.setKeyStoreType("PKCS12");

            // Enable client certificate authentication for sensitive endpoints
            // ssl.setClientAuth(Ssl.ClientAuth.WANT);

            factory.setSsl(ssl);
        };
    }

    @PostConstruct
    public void validateTLSConfiguration() {
        // Startup validation to ensure secure configuration
        String disabledAlgorithms = Security.getProperty("jdk.tls.disabledAlgorithms");

        if (!disabledAlgorithms.contains("SSLv3")) {
            logger.error("SECURITY ALERT: SSLv3 not disabled!");
            throw new SecurityException("Insecure TLS configuration detected");
        }

        if (!disabledAlgorithms.contains("TLSv1,") && !disabledAlgorithms.contains("TLSv1 ")) {
            logger.error("SECURITY ALERT: TLS 1.0 not disabled!");
            throw new SecurityException("Insecure TLS configuration detected");
        }

        logger.info("TLS security configuration validated successfully");
    }
}
```

