Server-side TLS configuration in ASP.NET Core requires configuring Kestrel's HTTPS settings, including protocol versions, cipher suites, and certificate handling. This is critical for PCI DSS compliance and preventing downgrade attacks.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Net;
using System.Security.Authentication;
using System.Security.Cryptography.X509Certificates;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Server.Kestrel.Core;
using Microsoft.AspNetCore.Server.Kestrel.Https;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

namespace SecurePaymentApi
{
    public class Program
    {
        public static void Main(string[] args)
        {
            CreateHostBuilder(args).Build().Run();
        }

        public static IHostBuilder CreateHostBuilder(string[] args) =>
            Host.CreateDefaultBuilder(args)
                .ConfigureWebHostDefaults(webBuilder =>
                {
                    webBuilder.UseStartup<Startup>();
                    webBuilder.ConfigureKestrel(ConfigureKestrelSecurity);
                });

        private static void ConfigureKestrelSecurity(KestrelServerOptions options)
        {
            var configuration = options.ApplicationServices
                .GetRequiredService<IConfiguration>();
            var logger = options.ApplicationServices
                .GetRequiredService<ILogger<Program>>();

            options.ConfigureHttpsDefaults(httpsOptions =>
            {
                // SECURE: Enforce TLS 1.2 and TLS 1.3 only
                httpsOptions.SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13;

                // SECURE: Require client certificate for mTLS (optional)
                httpsOptions.ClientCertificateMode = ClientCertificateMode.AllowCertificate;

                // SECURE: Validate client certificates
                httpsOptions.ClientCertificateValidation = (certificate, chain, errors) =>
                {
                    if (errors != SslPolicyErrors.None)
                    {
                        logger.LogWarning(
                            "Client certificate validation failed: {Errors}", errors);
                        return false;
                    }
                    return true;
                };

                // SECURE: Load certificate from secure storage
                var certPath = configuration["Kestrel:Certificates:Default:Path"];
                var certPassword = configuration["Kestrel:Certificates:Default:Password"];

                if (!string.IsNullOrEmpty(certPath))
                {
                    httpsOptions.ServerCertificate = new X509Certificate2(
                        certPath, 
                        certPassword,
                        X509KeyStorageFlags.MachineKeySet);
                }
            });

            // SECURE: Configure specific endpoints with strong TLS
            options.Listen(IPAddress.Any, 443, listenOptions =>
            {
                listenOptions.UseHttps(httpsOptions =>
                {
                    httpsOptions.SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13;

                    // SECURE: Configure allowed cipher suites (Windows/.NET 5+)
                    httpsOptions.OnAuthenticate = (context, sslOptions) =>
                    {
                        // Strong cipher suites only
                        sslOptions.CipherSuitesPolicy = new CipherSuitesPolicy(
                            new[]
                            {
                                // TLS 1.3 cipher suites (strongest)
                                TlsCipherSuite.TLS_AES_256_GCM_SHA384,
                                TlsCipherSuite.TLS_AES_128_GCM_SHA256,
                                TlsCipherSuite.TLS_CHACHA20_POLY1305_SHA256,

                                // TLS 1.2 cipher suites (AEAD only)
                                TlsCipherSuite.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                                TlsCipherSuite.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
                                TlsCipherSuite.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                                TlsCipherSuite.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256
                            });
                    };
                });
            });

            // SECURE: Set request limits to prevent abuse
            options.Limits.MaxRequestBodySize = 10 * 1024 * 1024; // 10MB
            options.Limits.RequestHeadersTimeout = TimeSpan.FromSeconds(30);
        }
    }

    public class Startup
    {
        public void ConfigureServices(IServiceCollection services)
        {
            services.AddControllers();

            // SECURE: Add HSTS for production
            services.AddHsts(options =>
            {
                options.MaxAge = TimeSpan.FromDays(365);
                options.IncludeSubDomains = true;
                options.Preload = true;
            });
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            if (!env.IsDevelopment())
            {
                // SECURE: Enable HSTS in production
                app.UseHsts();
            }

            // SECURE: Force HTTPS redirect
            app.UseHttpsRedirection();

            // SECURE: Add security headers
            app.Use(async (context, next) =>
            {
                context.Response.Headers.Add(
                    "Strict-Transport-Security", 
                    "max-age=31536000; includeSubDomains; preload");
                context.Response.Headers.Add(
                    "X-Content-Type-Options", "nosniff");
                context.Response.Headers.Add(
                    "X-Frame-Options", "DENY");
                await next();
            });

            app.UseRouting();
            app.UseEndpoints(endpoints => endpoints.MapControllers());
        }
    }

    // TLS Monitoring Middleware
    public class TlsMonitoringMiddleware
    {
        private readonly RequestDelegate _next;
        private readonly ILogger<TlsMonitoringMiddleware> _logger;

        public TlsMonitoringMiddleware(
            RequestDelegate next, 
            ILogger<TlsMonitoringMiddleware> logger)
        {
            _next = next;
            _logger = logger;
        }

        public async Task InvokeAsync(HttpContext context)
        {
            var tlsVersion = context.Connection.GetTlsProtocolVersion();
            var cipherSuite = context.Connection.GetTlsCipherSuite();

            // MONITORING: Log TLS connection details
            _logger.LogInformation(
                "TLS Connection: Protocol={Protocol}, Cipher={Cipher}, Client={ClientIP}",
                tlsVersion,
                cipherSuite,
                context.Connection.RemoteIpAddress);

            // ALERTING: Warn on TLS 1.2 (prefer 1.3)
            if (tlsVersion == SslProtocols.Tls12)
            {
                _logger.LogWarning(
                    "Client connected with TLS 1.2 instead of TLS 1.3: {ClientIP}",
                    context.Connection.RemoteIpAddress);
            }

            await _next(context);
        }
    }
}
```

