**Why This Is Dangerous**:
- SSLv3 and TLS 1.0/1.1 have known cryptographic weaknesses exploited by POODLE, BEAST attacks
- Default cipher suites include weak algorithms (RC4, DES, export ciphers)
- Protocol downgrade attacks force connections to weakest supported version
- PCI DSS 3.2+ explicitly prohibits SSLv3 and TLS 1.0 for payment data

**SECURE VERSION**:

```javascript
const https = require('https');
const fs = require('fs');
const express = require('express');
const crypto = require('crypto');

const app = express();

// SECURE: Modern TLS configuration
const options = {
  key: fs.readFileSync('server.key'),
  cert: fs.readFileSync('server.crt'),
  ca: fs.readFileSync('ca-chain.crt'), // Full certificate chain

  // CRITICAL: Enforce minimum TLS 1.2 (TLS 1.3 preferred)
  minVersion: 'TLSv1.2',
  maxVersion: 'TLSv1.3',

  // Strong cipher suites only - TLS 1.3 and secure TLS 1.2 ciphers
  ciphers: [
    'TLS_AES_256_GCM_SHA384',
    'TLS_CHACHA20_POLY1305_SHA256',
    'TLS_AES_128_GCM_SHA256',
    'ECDHE-ECDSA-AES256-GCM-SHA384',
    'ECDHE-RSA-AES256-GCM-SHA384',
    'ECDHE-ECDSA-CHACHA20-POLY1305',
    'ECDHE-RSA-CHACHA20-POLY1305'
  ].join(':'),

  // Prefer server cipher order
  honorCipherOrder: true,

  // Enable secure ECDH curves
  ecdhCurve: 'X25519:P-256:P-384'
};

// Security headers middleware
app.use((req, res, next) => {
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload');
  next();
});

