Using default SSL/TLS settings in Java is dangerous because older JDK versions enable vulnerable protocols like SSLv3 and TLS 1.0 by default. The POODLE attack (CVE-2014-3566) demonstrated how attackers can exploit SSLv3's CBC padding to decrypt HTTPS traffic.

**VULNERABLE CODE**:

```java
import javax.net.ssl.*;
import java.io.*;
import java.net.URL;
import java.security.SecureRandom;

public class VulnerableHttpsClient {

    public String fetchData(String urlString) throws Exception {
        // VULNERABLE: Using default SSL context allows weak protocols
        SSLContext sslContext = SSLContext.getInstance("SSL");
        sslContext.init(null, null, new SecureRandom());

        HttpsURLConnection.setDefaultSSLSocketFactory(sslContext.getSocketFactory());

        URL url = new URL(urlString);
        HttpsURLConnection connection = (HttpsURLConnection) url.openConnection();

        // VULNERABLE: No protocol enforcement
        BufferedReader reader = new BufferedReader(
            new InputStreamReader(connection.getInputStream()));

        StringBuilder response = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            response.append(line);
        }
        reader.close();

        return response.toString();
    }

    // VULNERABLE: Explicitly enabling weak protocols
    public SSLSocket createWeakSocket(String host, int port) throws Exception {
        SSLSocketFactory factory = (SSLSocketFactory) SSLSocketFactory.getDefault();
        SSLSocket socket = (SSLSocket) factory.createSocket(host, port);

        // CRITICALLY VULNERABLE: Enabling deprecated protocols
        socket.setEnabledProtocols(new String[] {
            "SSLv3", "TLSv1", "TLSv1.1", "TLSv1.2"
        });

        return socket;
    }
}
```

**Attack Scenario**:
```text
1. Attacker performs MITM attack on network
2. Forces client/server to downgrade to SSLv3
3. Exploits CBC padding oracle vulnerability
4. Decrypts session cookies byte-by-byte (256 requests per byte)
5. Hijacks authenticated session
```

**Why This Is Dangerous**:
- SSLv3 is fundamentally broken by POODLE attack - no patch possible
- TLS 1.0 is vulnerable to BEAST attack (CVE-2011-3389) and lacks AEAD ciphers
- TLS 1.1 is deprecated and missing modern security features
- Default "SSL" context may negotiate weakest common protocol
- PCI DSS, HIPAA, and most compliance frameworks prohibit these protocols

**SECURE VERSION**:

```java
import javax.net.ssl.*;
import java.io.*;
import java.net.URL;
import java.security.KeyStore;
import java.security.SecureRandom;
import java.util.Arrays;
import java.util.logging.Logger;

public class SecureHttpsClient {
    private static final Logger logger = Logger.getLogger(SecureHttpsClient.class.getName());

    // Minimum required: TLS 1.2, recommended: TLS 1.3
    private static final String[] SECURE_PROTOCOLS = {"TLSv1.3", "TLSv1.2"};

    // Strong cipher suites only
    private static final String[] SECURE_CIPHER_SUITES = {
        "TLS_AES_256_GCM_SHA384",
        "TLS_AES_128_GCM_SHA256",
        "TLS_CHACHA20_POLY1305_SHA256",
        "TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256",
        "TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256"
    };

    private final SSLContext sslContext;

    public SecureHttpsClient() throws Exception {
        // SECURE: Explicitly request TLS protocol
        this.sslContext = SSLContext.getInstance("TLSv1.3");
        this.sslContext.init(null, createTrustManagers(), new SecureRandom());
    }

    private TrustManager[] createTrustManagers() throws Exception {
        // Use default trust store with proper certificate validation
        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init((KeyStore) null);
        return tmf.getTrustManagers();
    }

    public String fetchData(String urlString) throws Exception {
        SSLSocketFactory factory = new SecureSSLSocketFactory(sslContext.getSocketFactory());
        HttpsURLConnection.setDefaultSSLSocketFactory(factory);

        URL url = new URL(urlString);
        HttpsURLConnection connection = (HttpsURLConnection) url.openConnection();
        connection.setConnectTimeout(10000);
        connection.setReadTimeout(30000);

        // Verify hostname matches certificate
        connection.setHostnameVerifier(HttpsURLConnection.getDefaultHostnameVerifier());

        logger.info("Connecting with protocol: " + 
            ((SSLSocket) factory.createSocket()).getEnabledProtocols()[0]);

        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(connection.getInputStream()))) {
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line);
            }
            return response.toString();
        }
    }

    // Custom SSLSocketFactory that enforces secure protocols
    private static class SecureSSLSocketFactory extends SSLSocketFactory {
        private final SSLSocketFactory delegate;

        SecureSSLSocketFactory(SSLSocketFactory delegate) {
            this.delegate = delegate;
        }

        private SSLSocket configureSocket(SSLSocket socket) {
            // SECURE: Only allow TLS 1.2 and 1.3
            socket.setEnabledProtocols(SECURE_PROTOCOLS);

            // SECURE: Only allow strong cipher suites
            String[] availableCiphers = socket.getSupportedCipherSuites();
            String[] enabledCiphers = Arrays.stream(SECURE_CIPHER_SUITES)
                .filter(cipher -> Arrays.asList(availableCiphers).contains(cipher))
                .toArray(String[]::new);
            socket.setEnabledCipherSuites(enabledCiphers);

            return socket;
        }

        @Override
        public Socket createSocket(Socket s, String host, int port, boolean autoClose) 
                throws IOException {
            return configureSocket((SSLSocket) delegate.createSocket(s, host, port, autoClose));
        }

        // Implement other required methods...
        @Override public String[] getDefaultCipherSuites() { return SECURE_CIPHER_SUITES; }
        @Override public String[] getSupportedCipherSuites() { return SECURE_CIPHER_SUITES; }
        @Override public Socket createSocket(String h, int p) throws IOException { 
            return configureSocket((SSLSocket) delegate.createSocket(h, p)); 
        }
        @Override public Socket createSocket(String h, int p, java.net.InetAddress la, int lp) 
                throws IOException { 
            return configureSocket((SSLSocket) delegate.createSocket(h, p, la, lp)); 
        }
        @Override public Socket createSocket(java.net.InetAddress h, int p) throws IOException { 
            return configureSocket((SSLSocket) delegate.createSocket(h, p)); 
