// TLS Security Auditing and Monitoring
package com.example.secure.monitoring;

import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.net.ssl.SSLSession;
import javax.servlet.FilterChain;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.security.cert.X509Certificate;
import java.util.Arrays;
import java.util.List;
import java.util.logging.Logger;

@Component
public class TlsSecurityAuditFilter extends OncePerRequestFilter {

    private static final Logger logger = Logger.getLogger(TlsSecurityAuditFilter.class.getName());
    private static final List<String> WEAK_PROTOCOLS = Arrays.asList("SSLv3", "TLSv1", "TLSv1.1");

    private final Counter tlsConnectionCounter;
    private final Counter weakTlsAttemptCounter;

    public TlsSecurityAuditFilter(MeterRegistry registry) {
        this.tlsConnectionCounter = Counter.builder("tls.connections")
            .description("TLS connections by protocol version")
            .tag("type", "total")
            .register(registry);

        this.weakTlsAttemptCounter = Counter.builder("tls.weak.attempts")
            .description("Blocked weak TLS protocol attempts")
            .tag("severity", "high")
            .register(registry);
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, 
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws Exception {

        // Get SSL session information
        Object sslSessionAttr = request.getAttribute("javax.servlet.request.ssl_session");

        if (sslSessionAttr instanceof SSLSession) {
            SSLSession sslSession = (SSLSession) sslSessionAttr;
            String protocol = sslSession.getProtocol();
            String cipherSuite = sslSession.getCipherSuite();

            // Log TLS connection details
            logger.info(String.format("TLS Connection - Protocol: %s, Cipher: %s, Client: %s",
                protocol, cipherSuite, request.getRemoteAddr()));

            tlsConnectionCounter.increment();

            // Alert on weak protocols (shouldn't happen if configured correctly)
            if (WEAK_PROTOCOLS.contains(protocol)) {
                logger.severe(String.format(
                    "SECURITY ALERT: Weak TLS protocol detected - Protocol: %s, IP: %s",
                    protocol, request.getRemoteAddr()));
                weakTlsAttemptCounter.increment();

                // Block the request
                response.sendError(HttpServletResponse.SC_FORBIDDEN, 
                    "Insecure TLS protocol not allowed");
                return;
            }

            // Check for weak cipher suites
            if (cipherSuite.contains("RC4") || cipherSuite.contains("DES") || 
                cipherSuite.contains("NULL") || cipherSuite.contains("EXPORT")) {
                logger.severe(String.format(
                    "SECURITY ALERT: Weak cipher suite detected - Cipher: %s, IP: %s",
                    cipherSuite, request.getRemoteAddr()));

                response.sendError(HttpServletResponse.SC_FORBIDDEN,
                    "Insecure cipher suite not allowed");
                return;
            }

            // Log client certificate info for mTLS
            X509Certificate[] certs = (X509Certificate[]) request.getAttribute(
                "javax.servlet.request.X509Certificate");
            if (certs != null && certs.length > 0) {
                logger.info("Client certificate: " + certs[0].getSubjectX500Principal());
            }
        }

        // Add security headers
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("X-Frame-Options", "DENY");
        response.setHeader("X-XSS-Protection", "1; mode=block");

        filterChain.doFilter(request, response);
    }
}
