// SecureHTTPClient creates a production-ready HTTP client with strict TLS
func SecureHTTPClient() (*http.Client, error) {
	// Load custom CA certificates if needed (e.g., internal PKI)
	caCertPool, err := x509.SystemCertPool()
	if err != nil {
		return nil, fmt.Errorf("failed to load system CA pool: %w", err)
	}

	// Optionally add internal CA certificates
	if caCertPath := os.Getenv("CUSTOM_CA_CERT"); caCertPath != "" {
		caCert, err := os.ReadFile(caCertPath)
		if err != nil {
			return nil, fmt.Errorf("failed to read CA cert: %w", err)
		}
		if !caCertPool.AppendCertsFromPEM(caCert) {
			return nil, fmt.Errorf("failed to append CA cert")
		}
	}

	tlsConfig := &tls.Config{
		// CRITICAL: Minimum TLS 1.2 for all outbound connections
		MinVersion: tls.VersionTLS12,
		MaxVersion: tls.VersionTLS13,

		// NEVER disable certificate verification in production
		// InsecureSkipVerify: true, // VULNERABLE - DO NOT USE

		// Use system + custom CA certificates
		RootCAs: caCertPool,

		// Strong cipher suites only
		CipherSuites: []uint16{
			tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
			tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
			tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
			tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
		},

		// Prefer server cipher suites
		PreferServerCipherSuites: true,

		// Session ticket rotation
		SessionTicketsDisabled: false,
	}

	// Custom transport with secure defaults
	transport := &http.Transport{
		TLSClientConfig: tlsConfig,
		DialContext: (&net.Dialer{
			Timeout:   30 * time.Second,
			KeepAlive: 30 * time.Second,
		}).DialContext,
		TLSHandshakeTimeout:   10 * time.Second,
		ResponseHeaderTimeout: 10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		MaxIdleConns:          100,
		MaxIdleConnsPerHost:   10,
		IdleConnTimeout:       90 * time.Second,
		// Force HTTP/2 when available
		ForceAttemptHTTP2: true,
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   30 * time.Second,
		// Prevent open redirects
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return fmt.Errorf("stopped after 3 redirects")
			}
			return nil
		},
	}

	return client, nil
}

// TLSConnectionValidator wraps client with TLS version logging
type TLSConnectionValidator struct {
	client *http.Client
	logger *log.Logger
}

func NewTLSConnectionValidator(client *http.Client) *TLSConnectionValidator {
	return &TLSConnectionValidator{
		client: client,
		logger: log.New(os.Stdout, "[TLS-AUDIT] ", log.LstdFlags),
	}
}

func (v *TLSConnectionValidator) Get(ctx context.Context, url string) (*http.Response, error) {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	resp, err := v.client.Do(req)
	if err != nil {
		v.logger.Printf("FAILED connection to %s: %v", url, err)
		return nil, err
	}

	// Log TLS connection details for security monitoring
	if resp.TLS != nil {
		v.logTLSInfo(url, resp.TLS)

		// Alert on weak TLS versions (shouldn't happen with our config)
		if resp.TLS.Version < tls.VersionTLS12 {
			v.logger.Printf("SECURITY ALERT: Weak TLS version 0x%04x for %s", 
				resp.TLS.Version, url)
		}
	}

	return resp, nil
}

func (v *TLSConnectionValidator) logTLSInfo(url string, state *tls.ConnectionState) {
	versionName := tlsVersionName(state.Version)
	cipherName := tls.CipherSuiteName(state.CipherSuite)

	v.logger.Printf("Connected to %s | TLS: %s | Cipher: %s | ServerName: %s",
		url, versionName, cipherName, state.ServerName)

	// Log certificate info
	if len(state.PeerCertificates) > 0 {
		cert := state.PeerCertificates[0]
		v.logger.Printf("Certificate: Subject=%s, Issuer=%s, NotAfter=%s",
			cert.Subject.CommonName, cert.Issuer.CommonName, cert.NotAfter)
	}
}

func tlsVersionName(version uint16) string {
	switch version {
	case tls.VersionTLS13:
		return "TLS 1.3"
	case tls.VersionTLS12:
		return "TLS 1.2"
	case tls.VersionTLS11:
		return "TLS 1.1 (DEPRECATED)"
	case tls.VersionTLS10:
		return "TLS 1.0 (DEPRECATED)"
	case tls.VersionSSL30:
		return "SSLv3 (INSECURE)"
	default:
		return fmt.Sprintf("Unknown (0x%04x)", version)
	}
}

func main() {
	// Create secure client
	client, err := SecureHTTPClient()
	if err != nil {
		log.Fatalf("Failed to create secure client: %v", err)
	}

	// Wrap with TLS validator for monitoring
	validator := NewTLSConnectionValidator(client)

	// Make secure request
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	resp, err := validator.Get(ctx, "https://api.example.com/data")
	if err != nil {
		log.Fatalf("Request failed: %v", err)
	}
	defer resp.Body.Close()

	body, _ := io.ReadAll(resp.Body)
	fmt.Printf("Response: %s\n", body)
}
