// Layer 3: Certificate pinning for high-security endpoints
func pinCertificate(expectedPin string) func([][]byte, [][]*x509.Certificate) error {
    return func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
        if len(verifiedChains) == 0 || len(verifiedChains[0]) == 0 {
            return fmt.Errorf("no certificates to verify")
        }

        cert := verifiedChains[0][0]
        actualPin := sha256.Sum256(cert.RawSubjectPublicKeyInfo)
        actualPinBase64 := base64.StdEncoding.EncodeToString(actualPin[:])

        if actualPinBase64 != expectedPin {
            return fmt.Errorf("certificate pin mismatch")
        }
        return nil
    }
}
