            : HealthCheckResult.Healthy("TLS 1.2/1.3 only");
    });
```

- **Certificate expiration monitoring**:
```csharp
public class CertificateExpirationMonitor : BackgroundService
{
    private readonly ILogger<CertificateExpirationMonitor> _logger;
    private readonly X509Certificate2 _certificate;

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            var daysUntilExpiry = (_certificate.NotAfter - DateTime.UtcNow).Days;

            if (daysUntilExpiry <= 30)
            {
                _logger.LogCritical(
                    "TLS certificate expires in {Days} days! Immediate action required.",
                    daysUntilExpiry);
            }
            else if (daysUntilExpiry <= 90)
            {
                _logger.LogWarning(
                    "TLS certificate expires in {Days} days. Plan renewal.",
                    daysUntilExpiry);
            }

            await Task.Delay(TimeSpan.FromHours(24), stoppingToken);
        }
    }
}
